import{_ as a,c as e,o as s,a as n}from"./app.1e429f93.js";const k='{"title":"Validation Configuration","description":"","frontmatter":{},"headers":[{"level":2,"title":"$scope","slug":"scope"},{"level":2,"title":"$stopPropagation","slug":"stoppropagation"},{"level":2,"title":"$autoDirty","slug":"autodirty"},{"level":2,"title":"$lazy","slug":"lazy"},{"level":2,"title":"$registerAs","slug":"registeras"},{"level":2,"title":"$externalResults","slug":"externalresults"},{"level":2,"title":"$rewardEarly","slug":"rewardearly"}],"relativePath":"api/configuration.md","lastUpdated":1777558547462}',t={},o=n(`<h1 id="validation-configuration" tabindex="-1">Validation Configuration <a class="header-anchor" href="#validation-configuration" aria-hidden="true">#</a></h1><h2 id="scope" tabindex="-1">$scope <a class="header-anchor" href="#scope" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>{String | Boolean | Symbol | Number}</code></p></li><li><p><strong>Default:</strong> <code>true</code></p></li><li><p><strong>Usage:</strong></p><p>Defines a scope, which the component will use to collect validation results from child components and push them up to its parent, with the same scope. <code>true</code> means it collects all, <code>false</code> means it collects none.</p></li></ul><h2 id="stoppropagation" tabindex="-1">$stopPropagation <a class="header-anchor" href="#stoppropagation" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>{Boolean}</code></p></li><li><p><strong>Default:</strong> <code>false</code></p></li><li><p><strong>Usage:</strong></p><p>Should the component stop emitting its results up, no matter the scope. This is useful for complex forms, which should child validations, but not emit those validations with any parent forms.</p></li></ul><h2 id="autodirty" tabindex="-1">$autoDirty <a class="header-anchor" href="#autodirty" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>{Boolean}</code></p></li><li><p><strong>Default:</strong> <code>false</code></p></li><li><p><strong>Usage:</strong></p><p>Tells Vuelidate to track changes on the state automatically. No need to use <code>$model</code> or <code>$touch</code>.</p></li></ul><h2 id="lazy" tabindex="-1">$lazy <a class="header-anchor" href="#lazy" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>{Boolean}</code></p></li><li><p><strong>Default:</strong> <code>false</code></p></li><li><p><strong>Usage:</strong></p><p>When set to <code>false</code>, tells the validation rules to be called on init, otherwise they are lazy and only called when the field is dirty.</p></li></ul><h2 id="registeras" tabindex="-1">$registerAs <a class="header-anchor" href="#registeras" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>{String}</code></p></li><li><p><strong>Usage:</strong></p><p>Allow assigning a custom component registration name to a Vuelidate instance. This is used when a validation is registered in a parent validation form.</p></li></ul><h2 id="externalresults" tabindex="-1">$externalResults <a class="header-anchor" href="#externalresults" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>ServerErrors | Ref&lt;ServerErrors&gt; | UnwrapRef&lt;ServerErrors&gt;</code></p></li><li><p><strong>Usage:</strong></p><p>Pass an object, matching your state, that holds external validation errors. These can be from a backend validations or something else.</p></li><li><p><strong>Example:</strong></p></li></ul><div class="language-js"><pre><code><span class="token keyword">const</span> $externalResults <span class="token operator">=</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> state <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">number</span><span class="token operator">:</span> <span class="token number">0</span> <span class="token punctuation">}</span>
<span class="token keyword">const</span> validations <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">number</span><span class="token operator">:</span> <span class="token punctuation">{</span> required <span class="token punctuation">}</span> <span class="token punctuation">}</span>
<span class="token keyword">const</span> v$ <span class="token operator">=</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span>validations<span class="token punctuation">,</span> state<span class="token punctuation">,</span> <span class="token punctuation">{</span> $externalResults <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// some other logic</span>
$externalResults<span class="token punctuation">.</span>number <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;One error&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;Two Errors&#39;</span><span class="token punctuation">]</span>
<span class="token comment">// setting a value in \`$externalResults\` for the \`number\` property would cause that property to become invalid.</span>
<span class="token function">expect</span><span class="token punctuation">(</span>v$<span class="token punctuation">.</span>value<span class="token punctuation">.</span>number<span class="token punctuation">.</span>$invalid<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toBe</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span>
</code></pre></div><h2 id="rewardearly" tabindex="-1">$rewardEarly <a class="header-anchor" href="#rewardearly" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Usage:</strong></p><p>Turn on the <code>reward-early-punish-late</code> mode of Vuelidate. This mode will not set fields as <code>invalid</code> once they are <code>valid</code>, unless manually triggered, by <code>$commit</code> or <code>$validate</code> methods. See <a href="https://github.com/Logiclayer1111/vuelidate/issues/897" target="_blank" rel="noopener noreferrer">https://github.com/Logiclayer1111/vuelidate/issues/897</a></p></li></ul>`,16),l=[o];function r(p,i,c,u,d,h){return s(),e("div",null,l)}var m=a(t,[["render",r]]);export{k as __pageData,m as default};
